const today = new Date(); today.setHours(0,0,0,0);
const yesterday = new Date(today.getTime() - 24*60*60*1000);
const yISO = yesterday.toISOString().slice(0,10);
const tISO = today.toISOString().slice(0,10);
const rows = $input.all().map(i => i.json.fields);
const yesterdayHandoffs = rows.filter(r => r['Date Introduced'] === yISO);
const yesterdayOrders   = rows.filter(r => r.Status === 'order_placed' && r['Date First Order'] === yISO);
const totals = rows.reduce((acc, r) => {
  acc.total += 1;
  if (r.Status === 'order_placed') {
    acc.placed += 1;
    acc.revenue += Number(r['First Order Amount'] || 0);
  }
  return acc;
}, { total: 0, placed: 0, revenue: 0 });
const usd = n => new Intl.NumberFormat('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 }).format(n);
return [{ json: {
  yesterday: yISO,
  newHandoffs: yesterdayHandoffs.length,
  newOrders:   yesterdayOrders.length,
  newRevenue:  yesterdayOrders.reduce((s, r) => s + Number(r['First Order Amount'] || 0), 0),
  totalLeads:    totals.total,
  totalOrders:   totals.placed,
  totalRevenue:  totals.revenue,
  totalRevenueFmt: usd(totals.revenue)
}}];
